   697→/* ---------- Waiting Countdown ---------- */
   698→
   699→function WaitingCountdown() {
   700→  const [remaining, setRemaining] = useState(120);
   701→
   702→  useEffect(() => {
   703→    const timer = setInterval(() => {
   704→      setRemaining((s) => {
   705→        if (s <= 0) return 0;
   706→        return s - 1;
   707→      });
   708→    }, 1000);
   709→    return () => clearInterval(timer);
   710→  }, []);
   711→
   712→  const minutes = Math.floor(remaining / 60);
   713→  const seconds = remaining % 60;
   714→
   715→  return (
   716→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
   717→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
   718→    </p>
   719→  );
   720→}
