   626→  useEffect(() => {
   627→    const tick = () => {
   628→      holdRafRef.current = requestAnimationFrame(tick);
   629→
   630→      if (!holdGestureRef.current || !holdStartRef.current) return;
   631→
   632→      const now = Date.now();
   633→
   634→      // If gesture hasn't been seen in 300ms, cancel the hold
   635→      if (now - holdLastSeenRef.current > 300) {
   636→        holdGestureRef.current = null;
   637→        holdStartRef.current = null;
   638→        setPendingGestureType(null);
   639→        return;
   640→      }
   641→
   642→      // Hold completed → dispatch the gesture event
   643→      const elapsed = now - holdStartRef.current;
   644→      if (elapsed >= HOLD_DURATION_MS) {
   645→        const gestureType = holdGestureRef.current;
   646→
   647→        setLastGesture(gestureType);
   648→        gestureKeyRef.current += 1;
   649→        setGestureKey(gestureKeyRef.current);
