   623→  // ── Hold-to-confirm timer loop (rAF) ──
   624→  // The visual ring animation is CSS-driven; this loop only handles
   625→  // staleness cancellation and dispatching at completion.
   626→  useEffect(() => {
   627→    const tick = () => {
   628→      holdRafRef.current = requestAnimationFrame(tick);
   629→
   630→      if (!holdGestureRef.current || !holdStartRef.current) return;
   631→
   632→      const now = Date.now();
   633→
   634→      // If gesture hasn't been seen in 300ms, cancel the hold
   635→      if (now - holdLastSeenRef.current > 300) {
   636→        holdGestureRef.current = null;
   637→        holdStartRef.current = null;
   638→        setPendingGestureType(null);
   639→        return;
   640→      }
   641→
   642→      // Hold completed → dispatch the gesture event
   643→      const elapsed = now - holdStartRef.current;
   644→      if (elapsed >= HOLD_DURATION_MS) {
   645→        const gestureType = holdGestureRef.current;
   646→
   647→        setLastGesture(gestureType);
   648→        gestureKeyRef.current += 1;
   649→        setGestureKey(gestureKeyRef.current);
   650→
   651→        socket.emit("mirror_event", {
   652→          user_id: userId,
   653→          event: {
   654→            type: "gesture",
   655→            gesture: gestureType,
   656→            confidence: 1,
   657→            timestamp: Date.now(),
   658→          },
   659→        });
   660→
   661→        // Reset hold state
   662→        holdGestureRef.current = null;
   663→        holdStartRef.current = null;
   664→        setPendingGestureType(null);
   665→      }
   666→    };
   667→
   668→    holdRafRef.current = requestAnimationFrame(tick);
   669→    return () => cancelAnimationFrame(holdRafRef.current);
   670→  }, [userId]);
