   718→          break;
   719→
   720→        default: {
   721→          const num = parseInt(e.key);
   722→          if (num >= 1 && num <= 9 && num - 1 < canvasOutfits.length) {
   723→            setCanvasOutfitIndex(num - 1);
   724→          }
   725→        }
   726→      }
   727→    }
