   735→    if (!userId || isStarting || sessionActive) return;
   736→
   737→    // Unlock browser audio policy while we still have the user gesture context
   738→    const ctx = new AudioContext();
   739→    ctx.resume().then(() => ctx.close());
   740→
   741→    setIsStarting(true);
   742→    socket.emit("start_session", { user_id: userId });
   743→  }, [userId, isStarting, sessionActive]);
   744→
   745→  const handleSkipUser = useCallback(() => {
   746→    if (!activeUser) return;
