   787→        position: "relative",
   788→        width: "100vw",
   789→        height: "100vh",
   790→        background: "#000",
   791→        overflow: "hidden",
   792→      }}
   793→    >
   794→      {/* Hidden camera feed (1x1 pixel, invisible — only used for pose detection) */}
   795→      <video
   796→        ref={videoRef}
   797→        autoPlay
   798→        playsInline
   799→        muted
   800→        style={{
   801→          position: "absolute",
   802→          top: 0,
   803→          left: 0,
   804→          width: 1,
   805→          height: 1,
   806→          opacity: 0,
   807→          pointerEvents: "none",
   808→        }}
   809→      />
   810→
   811→      {/* === ATTRACT STATE === */}
   812→      {kioskState === "attract" && (
   813→        <div
   814→          style={{
   815→            position: "absolute",
   816→            inset: 0,
   817→            zIndex: 20,
   818→            display: "flex",
   819→            flexDirection: "column",
   820→            alignItems: "center",
   821→            justifyContent: "center",
   822→            background: "#000",
   823→          }}
   824→        >
   825→          <h1
   826→            style={{
   827→              color: "#fff",
   828→              fontSize: "3rem",
