   203→
   204→  // ── Queue events (drives attract <-> waiting) ──
   205→  useEffect(() => {
   206→    const handleQueueUpdated = (data: {
   207→      active_user: ActiveUser | null;
   208→      queue: Array<{ id: string; user_id: string; name: string; position: number; status: string }>;
   209→    }) => {
   210→      console.log("[MirrorV2] queue_updated:", data);
   211→      if (kioskState === "session") return;
   212→
   213→      if (kioskState === "recap") {
