   215→        return;
   216→      }
   217→
   218→      if (data.active_user) {
   219→        setActiveUser(data.active_user);
   220→        setKioskState("waiting");
   221→      } else {
   222→        setActiveUser(null);
   223→        setKioskState("attract");
   224→      }
   225→    };
   226→
   227→    socket.on("queue_updated", handleQueueUpdated);
   228→    return () => {
   229→      socket.off("queue_updated", handleQueueUpdated);
   230→    };
   231→  }, [kioskState]);
   232→
   233→  // ── 2-minute timeout in waiting state ──
   234→  useEffect(() => {
   235→    if (kioskState === "waiting" && activeUser) {
   236→      waitingTimerRef.current = setTimeout(() => {
   237→        console.log("[MirrorV2] Waiting timeout — auto-skipping user");
   238→        skipQueueUser(activeUser.id).catch(() => {});
   239→      }, WAITING_TIMEOUT_MS);
   240→    }
   241→    return () => {
   242→      if (waitingTimerRef.current) {
   243→        clearTimeout(waitingTimerRef.current);
   244→        waitingTimerRef.current = null;
   245→      }
   246→    };
   247→  }, [kioskState, activeUser]);
   248→
   249→  // ── Session active from backend ──
   250→  useEffect(() => {
   251→    const handleSessionActive = () => {
   252→      setKioskState("session");
   253→      setSessionActive(true);
   254→      setIsStarting(false);
   255→      setCanvasOutfits([]);
   256→      setCanvasOutfitIndex(0);
   257→      setCarouselItems([]);
   258→      setOutfitOpacity(1);
   259→      setSpeechText("");
   260→      setSpeechVisible(false);
   261→      mira.startSession();
   262→      stt.startListening();
   263→    };
   264→
   265→    socket.on("session_active", handleSessionActive);
   266→    return () => {
   267→      socket.off("session_active", handleSessionActive);
   268→    };
   269→    // eslint-disable-next-line react-hooks/exhaustive-deps
   270→  }, []);
   271→
   272→  // ── Mira speech events (sentence-level streaming) ──
   273→  useEffect(() => {
   274→    // Regex for sentence boundaries: .!? followed by a space or end of string
   275→    const SENTENCE_BOUNDARY = /[.!?](?:\s|$)/;
   276→
   277→    /**
   278→     * Flush complete sentences from the buffer to TTS.
   279→     * Returns any remaining partial sentence left in the buffer.
   280→     */
   281→    function flushSentences(buffer: string, emotion: string): string {
   282→      let remaining = buffer;
   283→
   284→      while (true) {
   285→        const match = SENTENCE_BOUNDARY.exec(remaining);
   286→        if (!match) break;
   287→
   288→        // Split at the sentence boundary (include the punctuation)
   289→        const endIdx = match.index + match[0].length;
   290→        const sentence = remaining.slice(0, endIdx).trim();
   291→        remaining = remaining.slice(endIdx);
   292→
   293→        if (sentence) {
   294→          // Capture sentence in closure for the onStart callback
   295→          const displaySentence = sentence;
   296→          mira.speakQueued(
   297→            sentence,
   298→            emotion as MiraEmotion,
   299→            () => {
   300→              // Fires when TTS actually starts playing this sentence
   301→              setSpeechText(displaySentence);
   302→              setSpeechVisible(true);
   303→              if (speechFadeTimerRef.current) {
   304→                clearTimeout(speechFadeTimerRef.current);
   305→              }
   306→            },
   307→          );
   308→        }
   309→      }
   310→
   311→      return remaining;
   312→    }
   313→
   314→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   315→      // Ignore stale chunks from the pre-interrupt response
   316→      if (interruptedRef.current) {
   317→        if (data.is_chunk === false) {
   318→          interruptedRef.current = false; // Old response ended
   319→        }
   320→        return;
   321→      }
   322→
   323→      // Fallback session detection
   324→      if (!sessionActive && !isStarting) {
   325→        setKioskState("session");
   326→        setSessionActive(true);
   327→        setIsStarting(false);
   328→        mira.startSession();
   329→        stt.startListening();
   330→      }
   331→
   332→      if (data.is_chunk !== false) {
   333→        // ── Streaming chunk ──
   334→        if (!data.text) return;
   335→
   336→        sentenceBufferRef.current += data.text;
   337→
   338→        // Detect emotion from keywords in accumulated text
   339→        if (!emotionDetectedRef.current) {
   340→          const detected = detectEmotionFromText(sentenceBufferRef.current);
   341→          if (detected !== "idle") {
   342→            currentEmotionRef.current = detected;
   343→            emotionDetectedRef.current = true;
   344→          }
   345→        }
   346→
   347→        // Flush any complete sentences to TTS immediately
   348→        sentenceBufferRef.current = flushSentences(
   349→          sentenceBufferRef.current,
   350→          currentEmotionRef.current,
   351→        );
   352→      } else {
   353→        // ── End of message ──
   354→        if (data.text) {
   355→          sentenceBufferRef.current += data.text;
   356→        }
   357→
   358→        // Detect emotion if we haven't yet (short responses)
   359→        if (!emotionDetectedRef.current) {
   360→          currentEmotionRef.current = detectEmotionFromText(sentenceBufferRef.current);
   361→        }
   362→
   363→        // Flush any remaining text as the final sentence
   364→        const remainder = sentenceBufferRef.current.trim();
   365→        if (remainder) {
   366→          const displayRemainder = remainder;
   367→          mira.speakQueued(
   368→            remainder,
   369→            currentEmotionRef.current as MiraEmotion,
   370→            () => {
   371→              // Fires when TTS actually starts playing this sentence
   372→              setSpeechText(displayRemainder);
   373→              setSpeechVisible(true);
   374→              if (speechFadeTimerRef.current) {
   375→                clearTimeout(speechFadeTimerRef.current);
   376→              }
   377→            },
   378→          );
   379→        }
   380→
   381→        // Signal end of queue — drain callback will reset avatar state
   382→        mira.flushQueue();
   383→
   384→        // Reset for next response
   385→        sentenceBufferRef.current = "";
   386→        currentEmotionRef.current = "idle";
   387→        emotionDetectedRef.current = false;
   388→      }
   389→    };
   390→
   391→    socket.on("mira_speech", handleSpeech);
   392→    return () => {
   393→      socket.off("mira_speech", handleSpeech);
   394→    };
   395→    // eslint-disable-next-line react-hooks/exhaustive-deps
   396→  }, [sessionActive, isStarting]);
   397→
   398→  // Fade out speech text 2s after mira stops speaking
   399→  useEffect(() => {
   400→    if (!mira.isSpeaking && speechVisible) {
   401→      speechFadeTimerRef.current = setTimeout(() => {
   402→        setSpeechVisible(false);
   403→      }, 2000);
   404→    }
   405→    return () => {
   406→      if (speechFadeTimerRef.current) {
   407→        clearTimeout(speechFadeTimerRef.current);
   408→        speechFadeTimerRef.current = null;
   409→      }
   410→    };
   411→  }, [mira.isSpeaking, speechVisible]);
   412→
   413→  // ── Tool result events (product recommendations) ──
   414→  useEffect(() => {
   415→    const handleToolResult = (data: {
   416→      type?: string;
   417→      tool?: string;
   418→      items?: { title: string; price?: string; [key: string]: unknown }[];
