   465→  }, []);
   466→
   467→  // ── Session ended — show recap ──
   468→  useEffect(() => {
   469→    const handleSessionEnded = (data?: {
   470→      summary?: string;
   471→      liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
   472→      stats?: { items_shown: number; likes: number; dislikes: number };
   473→      user_name?: string;
   474→    }) => {
   475→      stt.stopListening();
