   485→        setKioskState("recap");
   486→      } else {
   487→        mira.stopSession();
   488→        setActiveUser(null);
   489→        setKioskState("attract");
   490→      }
   491→    };
   492→
   493→    socket.on("session_ended", handleSessionEnded);
   494→    return () => {
   495→      socket.off("session_ended", handleSessionEnded);
   496→    };
   497→    // eslint-disable-next-line react-hooks/exhaustive-deps
   498→  }, []);
   499→
   500→  // ── Force end from admin ──
   501→  useEffect(() => {
   502→    const handleForceEnd = (data: { user_id?: string }) => {
   503→      if (userId && data.user_id === userId) {
   504→        socket.emit("end_session", { user_id: userId });
   505→      }
   506→    };
   507→
   508→    socket.on("session_force_end", handleForceEnd);
   509→    return () => {
   510→      socket.off("session_force_end", handleForceEnd);
   511→    };
   512→  }, [userId]);
   513→
   514→  // ── Flush queued transcripts when mira stops speaking ──
   515→  useEffect(() => {
   516→    if (!mira.isSpeaking && pendingTranscriptRef.current && userId) {
   517→      socket.emit("mirror_event", {
   518→        user_id: userId,
   519→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   520→      });
   521→      pendingTranscriptRef.current = null;
   522→    }
   523→  }, [mira.isSpeaking, userId]);
   524→
   525→  // ── Forward final STT transcripts (interrupt Mira if speaking) ──
   526→  useEffect(() => {
   527→    if (!stt.transcript || !userId) return;
   528→
   529→    if (mira.isSpeaking) {
   530→      // INTERRUPT: stop TTS/avatar and tell backend to abort the stream
   531→      mira.stop();
   532→      interruptedRef.current = true;
   533→      sentenceBufferRef.current = "";
   534→      currentEmotionRef.current = "idle";
   535→      emotionDetectedRef.current = false;
   536→      setSpeechText("");
   537→      setSpeechVisible(false);
   538→      socket.emit("interrupt", { user_id: userId });
   539→    }
   540→
   541→    // Always send transcript immediately (whether interrupting or not)
   542→    socket.emit("mirror_event", {
   543→      user_id: userId,
   544→      event: { type: "voice", transcript: stt.transcript },
   545→    });
   546→    pendingTranscriptRef.current = null;
   547→    // eslint-disable-next-line react-hooks/exhaustive-deps
   548→  }, [stt.transcript, userId]);
   549→
   550→  // ── Snapshot handler ──
   551→  useEffect(() => {
   552→    const handleSnapshotRequest = () => {
   553→      const video = videoRef.current;
   554→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   555→
   556→      const canvas = document.createElement("canvas");
   557→      canvas.width = video.videoWidth;
   558→      canvas.height = video.videoHeight;
   559→      const ctx = canvas.getContext("2d");
   560→      if (!ctx) return;
   561→
   562→      ctx.drawImage(video, 0, 0);
   563→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   564→      const base64 = dataUrl.split(",")[1];
   565→
   566→      socket.emit("mirror_event", {
   567→        user_id: userId,
   568→        event: { type: "snapshot", image_base64: base64 },
   569→      });
   570→    };
   571→
   572→    socket.on("request_snapshot", handleSnapshotRequest);
   573→    return () => {
   574→      socket.off("request_snapshot", handleSnapshotRequest);
   575→    };
   576→  }, [videoRef, userId]);
   577→
   578→  // ── Gesture handler ──
   579→  const handleGesture = useCallback(
   580→    (gesture: DetectedGesture) => {
   581→      // Swipes → dispatch immediately (unchanged behavior)
   582→      if (gesture.type === "swipe_left" || gesture.type === "swipe_right") {
   583→        setLastGesture(gesture.type);
   584→        gestureKeyRef.current += 1;
   585→        setGestureKey(gestureKeyRef.current);
   586→
   587→        if (canvasOutfits.length > 1) {
   588→          if (gesture.type === "swipe_left") {
   589→            setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   590→          } else if (gesture.type === "swipe_right") {
   591→            setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   592→          }
   593→        }
   594→
   595→        socket.emit("mirror_event", {
   596→          user_id: userId,
   597→          event: {
   598→            type: "gesture",
   599→            gesture: gesture.type,
   600→            confidence: gesture.confidence,
   601→            timestamp: gesture.timestamp,
   602→          },
   603→        });
   604→        return;
   605→      }
   606→
   607→      // Thumbs → hold-to-confirm (update last-seen time each frame)
   608→      const now = Date.now();
   609→      holdLastSeenRef.current = now;
   610→
   611→      // If gesture type changed, reset and start a fresh hold
   612→      if (holdGestureRef.current !== gesture.type) {
   613→        holdGestureRef.current = gesture.type;
   614→        holdStartRef.current = now;
   615→        setPendingGestureType(gesture.type);
   616→        holdKeyRef.current += 1;
   617→        setHoldKey(holdKeyRef.current);
   618→      }
   619→    },
   620→    [userId, canvasOutfits.length],
   621→  );
   622→
   623→  // ── Hold-to-confirm timer loop (rAF) ──
   624→  // The visual ring animation is CSS-driven; this loop only handles
   625→  // staleness cancellation and dispatching at completion.
   626→  useEffect(() => {
   627→    const tick = () => {
   628→      holdRafRef.current = requestAnimationFrame(tick);
   629→
   630→      if (!holdGestureRef.current || !holdStartRef.current) return;
   631→
   632→      const now = Date.now();
   633→
   634→      // If gesture hasn't been seen in 300ms, cancel the hold
   635→      if (now - holdLastSeenRef.current > 300) {
   636→        holdGestureRef.current = null;
   637→        holdStartRef.current = null;
   638→        setPendingGestureType(null);
   639→        return;
   640→      }
   641→
   642→      // Hold completed → dispatch the gesture event
   643→      const elapsed = now - holdStartRef.current;
   644→      if (elapsed >= HOLD_DURATION_MS) {
   645→        const gestureType = holdGestureRef.current;
   646→
   647→        setLastGesture(gestureType);
   648→        gestureKeyRef.current += 1;
   649→        setGestureKey(gestureKeyRef.current);
   650→
   651→        socket.emit("mirror_event", {
   652→          user_id: userId,
   653→          event: {
   654→            type: "gesture",
   655→            gesture: gestureType,
   656→            confidence: 1,
   657→            timestamp: Date.now(),
   658→          },
   659→        });
   660→
   661→        // Reset hold state
   662→        holdGestureRef.current = null;
   663→        holdStartRef.current = null;
   664→        setPendingGestureType(null);
   665→      }
   666→    };
   667→
   668→    holdRafRef.current = requestAnimationFrame(tick);
   669→    return () => cancelAnimationFrame(holdRafRef.current);
   670→  }, [userId]);
   671→
   672→  useGestureRecognizer({
   673→    videoRef,
   674→    isVideoReady: isCameraReady,
   675→    onGesture: handleGesture,
   676→  });
   677→
   678→  // ── Keyboard shortcuts ──
   679→  useEffect(() => {
   680→    function handleKeyDown(e: KeyboardEvent) {
   681→      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) {
   682→        return;
   683→      }
   684→
   685→      switch (e.key) {
   686→        case "d":
   687→        case "D":
   688→          setDebugMode((d) => {
   689→            console.log(`[Mirror] Debug overlay ${d ? "OFF" : "ON"}`);
   690→            return !d;
   691→          });
   692→          break;
   693→
   694→        case "f":
   695→        case "F":
   696→          if (document.fullscreenElement) {
   697→            document.exitFullscreen();
   698→          } else {
   699→            document.documentElement.requestFullscreen();
   700→          }
   701→          break;
   702→
   703→        case "ArrowLeft":
   704→          if (canvasOutfits.length > 1) {
   705→            setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   706→          }
   707→          break;
   708→
   709→        case "ArrowRight":
   710→          if (canvasOutfits.length > 1) {
   711→            setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   712→          }
   713→          break;
   714→
   715→        case "r":
   716→        case "R":
   717→          setCanvasOutfitIndex(0);
   718→          break;
   719→
   720→        default: {
   721→          const num = parseInt(e.key);
   722→          if (num >= 1 && num <= 9 && num - 1 < canvasOutfits.length) {
   723→            setCanvasOutfitIndex(num - 1);
   724→          }
   725→        }
   726→      }
   727→    }
   728→
   729→    window.addEventListener("keydown", handleKeyDown);
   730→    return () => window.removeEventListener("keydown", handleKeyDown);
   731→  }, [canvasOutfits.length]);
   732→
   733→  // ── Start session handler ──
   734→  const handleStartSession = useCallback(() => {
   735→    if (!userId || isStarting || sessionActive) return;
   736→
   737→    // Unlock browser audio policy while we still have the user gesture context
   738→    const ctx = new AudioContext();
   739→    ctx.resume().then(() => ctx.close());
   740→
   741→    setIsStarting(true);
   742→    socket.emit("start_session", { user_id: userId });
   743→  }, [userId, isStarting, sessionActive]);
   744→
   745→  const handleSkipUser = useCallback(() => {
   746→    if (!activeUser) return;
   747→    skipQueueUser(activeUser.id).catch(() => {});
   748→  }, [activeUser]);
   749→
   750→  // ── Carousel gesture callback ──
   751→  const handleCarouselGesture = useCallback(
   752→    (gesture: GestureType, item: ProductCard) => {
   753→      socket.emit("mirror_event", {
   754→        user_id: userId,
   755→        event: {
   756→          type: "gesture",
   757→          gesture,
   758→          product_id: item.product_id,
   759→          product_title: item.title,
   760→        },
   761→      });
   762→    },
   763→    [userId],
   764→  );
   765→
   766→  // ── Dismiss recap ──
   767→  const handleRecapDismiss = useCallback(() => {
   768→    mira.stopSession();
   769→    setRecapData(null);
   770→
   771→    const pending = pendingQueueRef.current;
   772→    pendingQueueRef.current = undefined;
   773→
   774→    if (pending) {
   775→      setActiveUser(pending);
   776→      setKioskState("waiting");
   777→    } else {
   778→      setActiveUser(null);
   779→      setKioskState("attract");
   780→    }
   781→    // eslint-disable-next-line react-hooks/exhaustive-deps
   782→  }, []);
   783→
   784→  return (
   785→    <main
   786→      style={{
   787→        position: "relative",
   788→        width: "100vw",
   789→        height: "100vh",
   790→        background: "#000",
   791→        overflow: "hidden",
   792→      }}
   793→    >
   794→      {/* Hidden camera feed (1x1 pixel, invisible — only used for pose detection) */}
   795→      <video
   796→        ref={videoRef}
   797→        autoPlay
   798→        playsInline
   799→        muted
   800→        style={{
   801→          position: "absolute",
   802→          top: 0,
   803→          left: 0,
   804→          width: 1,
   805→          height: 1,
   806→          opacity: 0,
   807→          pointerEvents: "none",
   808→        }}
   809→      />
   810→
   811→      {/* === ATTRACT STATE === */}
   812→      {kioskState === "attract" && (
   813→        <div
   814→          style={{
   815→            position: "absolute",
   816→            inset: 0,
   817→            zIndex: 20,
   818→            display: "flex",
   819→            flexDirection: "column",
   820→            alignItems: "center",
   821→            justifyContent: "center",
   822→            background: "#000",
   823→          }}
   824→        >
   825→          <h1
   826→            style={{
   827→              color: "#fff",
   828→              fontSize: "3rem",
   829→              fontWeight: 700,
   830→              marginBottom: 8,
   831→              letterSpacing: "-0.02em",
   832→            }}
   833→          >
   834→            Mirrorless
   835→          </h1>
   836→          <p style={{ color: "rgba(255,255,255,0.6)", fontSize: "1.2rem", marginBottom: 40 }}>
   837→            Your AI stylist
   838→          </p>
   839→
   840→          <div
   841→            style={{
   842→              background: "#fff",
   843→              borderRadius: 16,
   844→              padding: 20,
   845→              marginBottom: 24,
   846→            }}
   847→          >
   848→            <QRCodeSVG
   849→              value={PHONE_URL}
   850→              size={180}
   851→              level="M"
   852→              includeMargin={false}
   853→            />
   854→          </div>
   855→
   856→          <p style={{ color: "rgba(255,255,255,0.4)", fontSize: "0.9rem" }}>
   857→            Scan the QR code with your phone
   858→          </p>
   859→        </div>
   860→      )}
   861→
   862→      {/* === WAITING STATE === */}
   863→      {kioskState === "waiting" && activeUser && (
   864→        <div
   865→          style={{
   866→            position: "absolute",
   867→            inset: 0,
   868→            zIndex: 20,
   869→            display: "flex",
   870→            flexDirection: "column",
   871→            alignItems: "center",
   872→            justifyContent: "center",
   873→            background: "#000",
   874→          }}
   875→        >
   876→          <p style={{ color: "rgba(255,255,255,0.5)", fontSize: "1rem", marginBottom: 8 }}>
   877→            Up next
   878→          </p>
   879→          <h2 style={{ color: "#fff", fontSize: "2.5rem", fontWeight: 700, marginBottom: 40 }}>
   880→            {activeUser.name}
   881→          </h2>
