   887→                padding: "16px 48px",
   888→                fontSize: "1.2rem",
   889→                fontWeight: 600,
   890→                color: "#fff",
   891→                background: "rgba(100, 140, 255, 0.8)",
   892→                border: "none",
   893→                borderRadius: 12,
   894→                cursor: "pointer",
   895→                boxShadow: "0 4px 20px rgba(100, 140, 255, 0.4)",
   896→              }}
   897→            >
   898→              {isStarting ? "Starting..." : "Start Session"}
   899→            </button>
   900→            <button
   901→              onClick={handleSkipUser}
   902→              style={{
   903→                padding: "16px 32px",
   904→                fontSize: "1.2rem",
   905→                fontWeight: 600,
   906→                color: "#fff",
   907→                background: "rgba(255, 255, 255, 0.15)",
   908→                border: "1px solid rgba(255,255,255,0.3)",
   909→                borderRadius: 12,
   910→                cursor: "pointer",
   911→              }}
   912→            >
   913→              Skip
   914→            </button>
   915→          </div>
   916→          <WaitingCountdown />
   917→        </div>
   918→      )}
   919→
   920→      {/* === SESSION STATE === */}
   921→
   922→      {/* Clothing overlay canvas (z-5) */}
   923→      {activeCanvasOutfit.length > 0 && currentPose && (
   924→        <div style={{ position: "absolute", inset: 0, zIndex: 5, transition: "opacity 500ms ease", opacity: outfitOpacity }}>
   925→          <ClothingCanvas
   926→            pose={currentPose}
   927→            items={activeCanvasOutfit}
   928→            width={CANVAS_WIDTH}
   929→            height={CANVAS_HEIGHT}
   930→            onFitStatus={handleFitStatus}
   931→          />
   932→        </div>
   933→      )}
   934→
   935→      {/* Debug overlay (z-6 normally, z-50 when active to render above attract/waiting overlays) */}
   936→      <div style={{ position: "absolute", inset: 0, zIndex: debugMode ? 50 : 6 }}>
   937→        <DebugOverlay
   938→          pose={currentPose}
   939→          items={activeCanvasOutfit}
   940→          width={CANVAS_WIDTH}
   941→          height={CANVAS_HEIGHT}
   942→          visible={debugMode}
   943→        />
   944→      </div>
   945→
   946→      {/* Mira Video Avatar (z-10, top-right corner) */}
   947→      {sessionActive && (
   948→        <div
   949→          style={{
   950→            position: "absolute",
   951→            top: 24,
   952→            right: 24,
   953→            zIndex: 10,
   954→          }}
   955→        >
   956→          <MiraVideoAvatar
   957→            emotion={mira.emotion}
   958→            state={mira.avatarState}
   959→            size={180}
   960→          />
   961→        </div>
   962→      )}
   963→
   964→      {/* Speech display (z-10, bottom-center, above price strip) */}
   965→      {sessionActive && (
   966→        <SpeechDisplay text={speechText} visible={speechVisible} />
   967→      )}
   968→
   969→      {/* Product carousel (z-10, bottom) — hidden when canvas overlay is active on body */}
   970→      {sessionActive && carouselItems.length > 0 && !(activeCanvasOutfit.length > 0 && currentPose) && (
   971→        <ProductCarousel items={carouselItems} onGesture={handleCarouselGesture} />
   972→      )}
   973→
   974→      {/* Price strip (z-15, bottom) — shows when canvas overlay is active */}
   975→      {sessionActive && activePriceItems.length > 0 && activeCanvasOutfit.length > 0 && currentPose && (
   976→        <PriceStrip items={activePriceItems} />
   977→      )}
   978→
   979→      {/* Outfit dots (z-18, bottom) */}
   980→      <OutfitDots count={canvasOutfits.length} activeIndex={canvasOutfitIndex} />
   981→
   982→      {/* Voice indicator for user STT (z-15, bottom-left) */}
   983→      {sessionActive && (
   984→        <VoiceIndicator
   985→          isListening={stt.isListening}
   986→          interimTranscript={stt.interimTranscript}
   987→        />
   988→      )}
   989→
   990→      {/* Gesture visual feedback (z-20, center) */}
   991→      <GestureIndicator
   992→        gesture={lastGesture}
   993→        gestureKey={gestureKey}
   994→        pendingGesture={pendingGestureType}
   995→        holdKey={holdKey}
   996→      />
   997→
   998→      {/* === RECAP STATE === (z-25) */}
   999→      {recapData && (
  1000→        <SessionRecap
  1001→          summary={recapData.summary}
  1002→          likedItems={recapData.liked_items || []}
  1003→          stats={recapData.stats}
  1004→          userName={recapData.user_name}
  1005→          onDismiss={handleRecapDismiss}
  1006→        />
  1007→      )}
  1008→
  1009→      {/* Fit status indicator (bottom-right, debug-only) */}
  1010→      {debugMode && fitStatuses.size > 0 && (
  1011→        <div
  1012→          style={{
  1013→            position: "absolute",
  1014→            bottom: 20,
  1015→            right: 20,
  1016→            padding: "8px 12px",
  1017→            background: "rgba(0,0,0,0.7)",
  1018→            borderRadius: 8,
  1019→            color: "#fff",
  1020→            fontSize: "0.75rem",
  1021→            zIndex: 30,
  1022→            fontFamily: "monospace",
  1023→          }}
  1024→        >
  1025→          {Array.from(fitStatuses.entries()).map(([id, method]) => (
  1026→            <div key={id}>
  1027→              {id.slice(0, 8)}: {method === "precise" ? "anchor" : "quad"}
  1028→            </div>
  1029→          ))}
  1030→        </div>
  1031→      )}
  1032→    </main>
  1033→  );
  1034→}
  1035→
  1036→/* ---------- Waiting Countdown ---------- */
  1037→
  1038→function WaitingCountdown() {
  1039→  const [remaining, setRemaining] = useState(120);
  1040→
  1041→  useEffect(() => {
  1042→    const timer = setInterval(() => {
  1043→      setRemaining((s) => {
  1044→        if (s <= 0) return 0;
  1045→        return s - 1;
  1046→      });
  1047→    }, 1000);
  1048→    return () => clearInterval(timer);
  1049→  }, []);
  1050→
  1051→  const minutes = Math.floor(remaining / 60);
  1052→  const seconds = remaining % 60;
  1053→
  1054→  return (
  1055→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
  1056→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
  1057→    </p>
  1058→  );
  1059→}
